fields.collector:
$warnIds=8003,8006,8021,8024,8028,8038
$blockIds=8004,8007,8021,8024,8029,8040
$allIds=$warnIds+$blockIds|Sort-Object -Unique
$t=(Get-Date).AddHours(-24)
$logs=@(@{L='Microsoft-Windows-AppLocker/EXE and DLL';T='Application'},@{L='Microsoft-Windows-AppLocker/MSI and Script';T='Script'})
$raw=foreach($s in $logs){
 Get-WinEvent -FilterHashtable @{LogName=$s.L;Id=$allIds;StartTime=$t} -EA SilentlyContinue|%{
  $d=([xml]$_.ToXml()).Event.UserData.RuleAndFileData
  $rp=[string]$d.FilePath
  $fp=$rp -replace '%OSDRIVE%',$env:SystemDrive
  [pscustomobject]@{Ev=$_;Type=$s.T;Raw=$rp;Path=$fp}
 }
}
$pc=@{}
$raw|%{if($_.Raw){$pc[$_.Raw]=[int]$pc[$_.Raw]+1}}
$events=foreach($e in ($raw|Sort-Object {$_.Ev.RecordId} -Unique)){
 $ev=$e.Ev;$fp=$e.Path;$fn=if($fp){Split-Path -Leaf $fp}
 if([string]::IsNullOrEmpty($fp) -or $fp -match 'PSSCRIPTPOLICYTEST' -or -not(Test-Path $fp -EA SilentlyContinue)){continue}
 $vi=(Get-ItemProperty $fp -EA SilentlyContinue).VersionInfo
 $fd=if($vi.FileDescription){$vi.FileDescription}else{$fn}
 $pn=if($vi.ProductName){$vi.ProductName}else{$fd}
 $fv=if($vi.FileVersion){$vi.FileVersion}else{'Unavailable'}
 try{$fh=(Get-FileHash $fp -Algorithm SHA256 -EA Stop).Hash}catch{$fh='Access denied'}
 $fl=(Get-Item $fp -EA SilentlyContinue).Length
 $ai=Get-AppLockerFileInformation $fp -EA SilentlyContinue
 $pbn=$ai.Publisher.PublisherName
 if([string]::IsNullOrEmpty($pbn)){$pu='Unsigned';$fpub='N/A';$sg='No'}else{$pu=(($pbn -split ',')[0]).TrimStart('O=');$fpub=[string]$ai.Publisher;$sg='Yes'}
 if($sg -eq 'Yes' -and $pn -ne $fd){try{$pr=[string]($ai|New-AppLockerPolicy -RuleType Publisher -User Everyone -RuleNamePrefix $pn -XML -EA Stop)}catch{$pr='Unsigned Application'}}else{$pr='Unsigned Application'}
 try{$hr=[string]($ai|New-AppLockerPolicy -RuleType Hash -User Everyone -RuleNamePrefix $pn -XML -EA Stop)}catch{$hr=$null}
 try{$lr=[string]($ai|New-AppLockerPolicy -RuleType Path -User Everyone -RuleNamePrefix $pn -XML -EA Stop)}catch{$lr=$null}
 [pscustomobject]@{
  EventRecordId=[long]$ev.RecordId
  EventType=if($blockIds -contains $ev.Id){'Denied'}else{'Audited'}
  EventId=[int]$ev.Id
  EventMessage=$ev.Message
  RuleType=$e.Type
  FileDescription=$fd
  FileVersion=$fv
  ProductName=$pn
  FileHash=$fh
  FileName=$fn
  FilePath=$fp
  FileLength=$fl
  Publisher=$pu
  FullPublisher=$fpub
  FileUseCount=[int]$pc[$e.Raw]
  AppLockerPublisherRule=$pr
  AppLockerHashRule=$hr
  AppLockerPathRule=$lr
  Signed=$sg
 }
}
@($events)
